const isDanse = (el, val) => {
	if (val < 150) return false;
	if (el.time) {
		el.time--;
		return false;
	}
	if (el.classList.contains('danse-jump')) return false;
	return true;
};

const onJumpEnd = function () {
	this.time = 1;
	this.classList.remove('danse-jump');
};

export default {
	state: () => ({
		jump: [],
		color: [],
	}),
	mutations: {
		addJumpElement(state, el) {
			if (!el) return;
			if (state.jump.find((_el) => el === _el)) return;

			el.time = 0;
			state.jump.push(el);
			el.addEventListener('animationend', onJumpEnd);
		},
		addColorElement(state, el) {
			if (!el) return;
			if (state.color.find((_el) => el === _el)) return;

			state.color.push(el);
		},
		resetAllElements(state) {
			state.jump.forEach(
				(el) => (el.classList.remove('danse-jump'), el.removeEventListener('animationend', onJumpEnd))
			);
			state.color.forEach((el) => (el.style.color = 'inherit'));
			state.jump = [];
			state.color = [];
		},
		setAllElements(state, uint8arr) {
			const arr = [...uint8arr];
			let i;

			i = 1;
			state.jump.forEach((el) => {
				isDanse(el, arr[i++ % arr.length]) ? el.classList.add('danse-jump') : '';
			});

			i = 1;
			state.color.forEach((el) => (el.style.color = `rgb(${arr[1]}, 255, ${arr[1]})`));
		},
	},
	actions: {},
	getters: {},
};
