<template>
	<transition name="loader">
		<div v-show="timeoutId" id="loader" class="text-white bg-dark">
			<div class="h-100 w-100 d-flex justify-content-center align-items-center">
				<canvas id="tree" width="500" height="400"></canvas>
			</div>
		</div>
	</transition>
</template>

<script>
	import { createNamespacedHelpers } from 'vuex';
	const { mapState } = createNamespacedHelpers('loader');

	export default {
		data() {
			return {
				canvas: null,
				ctx: null,
				timeoutId: null,
			};
		},
		computed: {
			...mapState({
				page: (state) => state.page,
			}),
		},
		watch: {
			page(newPage, oldPage) {
				if (!newPage.on) return;
				if (newPage.path === oldPage.path) return;
				clearTimeout(this.timeoutId);
				this.$tree.stop();
				this.$tree.start(this.canvas, this.ctx);

				this.timeoutId = setTimeout(() => {
					this.$tree.stop();
					this.timeoutId = null;
					this.$store.commit('loader/setLoader', { page: newPage.path, on: false });
				}, 1500);
			},
		},
		mounted() {
			const c = document.getElementById('tree');
			this.canvas = c;
			this.ctx = c.getContext('2d');
		},
	};
</script>

<style scoped>
	#loader {
		height: 100vh;
		width: 100vw;
		position: fixed;
		top: 0;
		left: 0;
		z-index: 5;
	}
	@keyframes slidein {
		0% {
			transform: translateX(-100vw);
		}
		100% {
			transform: translateX(0);
		}
	}
	@keyframes slideout {
		0% {
			transform: translateX(0);
		}
		100% {
			transform: translateX(100vw);
		}
	}
	.loader-enter-active {
		animation: slidein cubic-bezier(0.23, 1.47, 0.04, 0.81) 0.7s;
	}
	.loader-leave-active {
		animation: slideout cubic-bezier(0.23, 1.47, 0.04, 0.81) 0.7s;
	}
	/* canvas tree */
	#tree {
		width: 250px;
		height: 200px;
	}
</style>
