import { createRouter, createWebHistory } from 'vue-router';
import store from '@/store';

const routes = [
	{
		path: '/',
		name: 'Home',
		component: () => import('@/pages/Home.vue'),
	},
	{
		path: '/about-me',
		name: 'AboutMe',
		component: () => import('@/pages/AboutMe.vue'),
	},
	{
		path: '/works',
		name: 'Works',
		component: () => import('@/pages/Works.vue'),
	},
	{
		path: '/works/:name',
		name: 'Work',
		component: () => import('@/pages/Work.vue'),
	},
	{
		path: '/sketch',
		name: 'Sketch',
		component: () => import('@/pages/Sketch.vue'),
	},
];

const delay = (sec) => new Promise((resolve) => setTimeout(() => resolve(), sec * 1000));
const router = createRouter({
	history: createWebHistory(),
	routes,
});
router.beforeResolve(async (to, from, next) => {
	if (from.name && to.path == from.path) return next();
	if (from.path && to.path && from.path.search(/works\/.+$/) === 1 && to.path.search(/works$/) === 1) return next();

	store.commit('loader/setLoader', { path: to.path, on: true });
	await delay(0.5);
	return next();
});

export default router;
