<template>
	<nav class="navbar align-items-center justify-space-between bg-dark" id="app-nav" ref="nav">
		<div>
			<router-link class="navbar-brand m-0" to="/" @click="clickRoute" exact>
				<span class="highlight">WP</span>
			</router-link>
		</div>
		<div class="d-flex" id="app-nav-routes">
			<router-link v-for="page in pages" :key="page.url" :to="page.url" class="link" @click="clickRoute">
				<i class="bi app-nav-route-icons" :class="page.icon"></i>
			</router-link>
		</div>
		<AudioPlayer />
	</nav>
</template>

<script>
	import AudioPlayer from '@/components/AudioPlayer';

	export default {
		components: {
			AudioPlayer,
		},
		data() {
			return {
				pages: [
					{ url: '/about-me', icon: 'bi-person-badge' },
					{ url: '/works', icon: 'bi-grid-1x2' },
					{ url: '/sketch', icon: 'bi-brush' },
				],
				page: null,
			};
		},
		methods: {
			clickRoute(e) {
				const children = [...this.$refs.nav.querySelectorAll('a.link')];
				children.forEach((el) =>
					el.href !== e.currentTarget.href
						? el.classList.remove('router-link-active')
						: e.currentTarget.classList.add('router-link-active')
				);
			},
		},
	};
</script>

