<template>
	<div ref="icon" id="music-icon" class="cursor" @click="toggleMusic"></div>
	<audio :src="require('@/assets/memories.mp3')" ref="audio"></audio>
</template>

<script>
	export default {
		data() {
			return {
				animationId: null,
				analyser: null,
				audioCtx: null,
				source: null,
				dataArray: null,
			};
		},
		mounted() {
			const audio = this.$refs.audio;
			audio.volume = 0.1;
			audio.addEventListener('ended', this.stopMusic);
			audio.addEventListener('pause', this.stopMusic);
			audio.addEventListener('playing', this.playMusic);
		},
		beforeUnmount() {
			const audio = this.$refs.audio;
			audio.removeEventListener('pause', this.stopMusic);
			audio.removeEventListener('ended', this.stopMusic);
			audio.removeEventListener('playing', this.playMusic);
		},
		methods: {
			toggleMusic() {
				const audio = this.$refs.audio;
				if (audio.paused) {
					this.audioCtx = this.audioCtx || new (window.AudioContext || window.webkitAudioContext)();
					this.source = this.source || this.audioCtx.createMediaElementSource(audio);
					this.analyser = this.analyser || this.audioCtx.createAnalyser();
					this.analyser.fftSize = 2048;

					this.source.connect(this.analyser);
					this.source.connect(this.audioCtx.destination);
					this.dataArray = this.dataArray || new Uint8Array(this.analyser.frequencyBinCount);

					audio.play();
				} else audio.pause();
			},
			playMusic() {
				if (this.animationId) this.stopMusic();

				this.animationId = requestAnimationFrame(this.loop);
			},
			stopMusic() {
				if (this.animationId) {
					cancelAnimationFrame(this.animationId);
					this.animationId = null;
					this.$refs.icon.style.backgroundPositionY = '25%';
					this.$store.commit('me/resetAllGages');
					this.$store.commit('danse/resetAllElements');
				}
			},
			loop() {
				const icon = this.$refs.icon;
				this.analyser.getByteFrequencyData(this.dataArray);
				this.$store.commit('me/setAllGages', this.dataArray);
				this.$store.commit('danse/setAllElements', this.dataArray);

				const barHight = Math.floor((this.dataArray[5] * 100) / 256);
				icon.style.backgroundPositionY = `${barHight + 25}%`;

				this.animationId = requestAnimationFrame(this.loop);
			},
		},
	};
</script>

<style lang="scss" scoped>
	@import '@/assets/styles/variables.scss';
	/* music icon */
	#music-icon {
		width: 2rem;
		height: 2rem;
		background-size: 100%;
		mask-size: 100%;
		background-position-y: 25%; /* 25 ~ 75 */
	}
</style>
