import * as _ from 'fxjs';

const make2d = (n) => _.map(() => [], _.range(n));

const groupByN = (list, n) => {
	const arr2d = make2d(n); // [[], [], [], ...]
	const cp_list = [...list];

	let i = 0;
	let el;
	while (cp_list.length) {
		el = cp_list.pop();
		arr2d[i].push(el);
		i = (i + 1) % n;
	}
	return arr2d;
};

export default {
	install(app) {
		app.config.globalProperties.$helper = {
			groupByN,
			filter: _.filter,
			go: _.go,
			map: _.map,
		};
	},
};
