import me from '@/me.json';
import axios from 'axios';
import * as _ from 'fxjs';
// import * as L from 'fxjs/Lazy';
import * as C from 'fxjs/Concurrency';

const fetchMostUsedLanguage = (githubId, works) =>
	_.go(
		works,
		_.map((w) => `https://api.github.com/repos/${githubId}/${w.name}/languages`),
		C.map((url) => axios.get(url)),
		_.map(({ data }) => data),
		_.reduce((acc, o) => {
			Object.entries(o).forEach(([k, v]) => {
				acc[k] = acc[k] ? acc[k] + v : v;
			});
			return acc;
		}),
		Object.entries,
		(entries) => {
			const total = entries.reduce((total, entry) => total + entry[1], 0);
			return _.map(([lang, lines]) => ({ name: lang, degree: `${Math.floor((lines / total) * 100)}%` }), entries);
		},
		_.filter((obj) => obj.degree != '0%')
	);

const original_skill = me.skill;
let original_most_used_langugage = [];

export default {
	state: () => ({
		...me,
		most_used_language: [],
	}),
	mutations: {
		initMostUsedLanguage(state, langs) {
			state.most_used_language = langs;
			original_most_used_langugage = langs;
		},
		resetAllGages(state) {
			state.skill = original_skill;
			state.most_used_language = original_most_used_langugage;
		},
		setAllGages(state, uint8arr) {
			let i = 3;
			const arr = [...uint8arr];
			const dataArr = arr.map((d) => `${Math.floor((d * 100) / 255)}%`);
			state.most_used_language = state.most_used_language.map((s) => ({
				...s,
				degree: dataArr[i++ % dataArr.length],
			}));
			state.skill = state.skill.map((s) => ({ ...s, degree: dataArr[i++ % dataArr.length] }));
		},
	},
	actions: {
		async initMostUsedLanguage({ commit, state, rootState }) {
			if (state.most_used_language.length) return;

			const langs = await fetchMostUsedLanguage(state.githubId, rootState.works);
			commit('initMostUsedLanguage', langs);
		},
	},
	getters: {},
};
